const body = $input.first().json.body || $input.first().json;
const blog = body.blog || {};
const pins = body.pinterest_pins || [];
const storeUrls = body.store_urls || {};
const brand = body.brand || {};
const productId = body.product_id;

// Validate blog data
if (!blog.post?.title || !blog.post?.introduction) {
  return [{ json: { error: true, message: 'Blog data missing required fields', received: Object.keys(blog) } }];
}

// Build complete WordPress-ready post content
const buildWordPressContent = (post, seo, productUrl) => {
  const sections = (post.sections || []).map(section => {
    const subsections = (section.subsections || []).map(sub =>
      `<h3>${sub.subheading}</h3>\n<p>${sub.content}</p>`
    ).join('\n');

    const list = section.has_list && section.list_items?.length ?
      `<ul>${section.list_items.map(item => `<li>${item}</li>`).join('')}</ul>` : '';

    return `<h2>${section.heading}</h2>\n<p>${section.content}</p>\n${subsections}\n${list}`;
  }).join('\n\n');

  const faqs = (post.faq_section?.faqs || []).map(faq =>
    `<details><summary><strong>${faq.question}</strong></summary><p>${faq.answer}</p></details>`
  ).join('\n');

  const content = `
<!-- wp:paragraph -->
<p>${post.introduction}</p>
<!-- /wp:paragraph -->

${sections}

<!-- wp:heading -->
<h2>${post.product_section?.heading || 'Get the Template'}</h2>
<!-- /wp:heading -->

<!-- wp:paragraph -->
<p>${post.product_section?.content || ''}</p>
<!-- /wp:paragraph -->

<!-- wp:buttons -->
<div class="wp-block-buttons">
  <div class="wp-block-button">
    <a class="wp-block-button__link" href="${productUrl}">${post.product_section?.cta_button_text || 'Get It Now'}</a>
  </div>
</div>
<!-- /wp:buttons -->

<!-- wp:heading -->
<h2>${post.faq_section?.heading || 'Frequently Asked Questions'}</h2>
<!-- /wp:heading -->

${faqs}

<!-- wp:paragraph -->
<p>${post.conclusion}</p>
<!-- /wp:paragraph -->

<!-- wp:separator -->
<hr class="wp-block-separator"/>
<!-- /wp:separator -->

<!-- wp:paragraph -->
<p><em>${post.author_bio}</em></p>
<!-- /wp:paragraph -->
  `;

  return content.trim();
};

const wpContent = buildWordPressContent(blog.post, blog.seo, storeUrls.primary);

// Build Yoast/RankMath SEO schema
const seoMeta = {
  title: blog.seo?.meta_title || blog.post?.title,
  description: blog.seo?.meta_description || '',
  focus_keyword: blog.seo?.primary_keyword || '',
  slug: blog.seo?.url_slug || blog.post?.title?.toLowerCase().replace(/[^a-z0-9]+/g,'-').replace(/^-|-$/g,''),
  schema_type: blog.seo?.schema_type || 'Article'
};

// Build FAQ schema JSON-LD
const faqSchema = {
  '@context': 'https://schema.org',
  '@type': 'FAQPage',
  'mainEntity': (blog.post?.faq_section?.faqs || []).map(faq => ({
    '@type': 'Question',
    'name': faq.question,
    'acceptedAnswer': { '@type': 'Answer', 'text': faq.answer }
  }))
};

return [{ json: {
  product_id: productId,
  brand,
  store_urls: storeUrls,
  wordpress: {
    title: blog.post?.title,
    content: wpContent,
    slug: seoMeta.slug,
    status: 'publish',
    categories: [brand.brand_name || 'Digital Products'],
    tags: blog.seo?.secondary_keywords || [],
    meta: {
      _yoast_wpseo_title: seoMeta.title,
      _yoast_wpseo_metadesc: seoMeta.description,
      _yoast_wpseo_focuskw: seoMeta.focus_keyword,
      rank_math_focus_keyword: seoMeta.focus_keyword,
      rank_math_description: seoMeta.description
    },
    faq_schema: JSON.stringify(faqSchema)
  },
  ghost: {
    title: blog.post?.title,
    html: wpContent.replace(/<!-- [^>]+ -->/g, ''),
    slug: seoMeta.slug,
    status: 'published',
    tags: (blog.seo?.secondary_keywords || []).map(kw => ({ name: kw })),
    meta_title: seoMeta.title,
    meta_description: seoMeta.description
  },
  seo_meta: seoMeta,
  pinterest_pins: pins,
  featured_image_prompt: blog.pinterest_pins?.[0]?.sd_prompt || '',
  full_blog: blog,
  _prepared_at: new Date().toISOString()
}}];

