// Determine which CMS was used and get the published URL
const wpResult = $('📝 Publish to WordPress').first().json;
const ghostResult = $('👻 Publish to Ghost (Alternative)').first().json;
const prepData = $('⚙️ Prep Blog for Publishing').first().json;
const imgResult = $('🔍 Poll Featured Image').first().json;

// Get blog URL from whichever platform succeeded
let blogUrl = null;
let platform = null;
let postId = null;

if (wpResult?.link && !wpResult?.code) {
  blogUrl = wpResult.link;
  platform = 'wordpress';
  postId = wpResult.id;
} else if (ghostResult?.posts?.[0]?.url) {
  blogUrl = ghostResult.posts[0].url;
  platform = 'ghost';
  postId = ghostResult.posts[0].id;
} else {
  // Fallback: construct URL from slug
  blogUrl = `YOUR_BLOG_URL/${prepData.seo_meta.slug}`;
  platform = 'unknown';
}

const featuredImageUrl = imgResult?.output?.[0] || null;

// Update Pinterest pins with actual blog URL
const pinsWithUrl = (prepData.pinterest_pins || []).map(pin => ({
  ...pin,
  link: blogUrl,
  image_url: featuredImageUrl
}));

return [{ json: {
  product_id: prepData.product_id,
  blog_published: !!blogUrl,
  blog_url: blogUrl,
  blog_platform: platform,
  post_id: postId,
  featured_image_url: featuredImageUrl,
  seo_meta: prepData.seo_meta,
  pinterest_pins: pinsWithUrl,
  store_urls: prepData.store_urls,
  brand: prepData.brand,
  _published_at: new Date().toISOString()
}}];

// Split Pinterest pins into separate items for parallel posting
const data = $input.first().json;
const pins = data.pinterest_pins || [];

if (pins.length === 0) {
  return [{ json: { ...data, no_pins: true } }];
}

return pins.map(pin => ({ json: { ...data, current_pin: pin } }));

// Generate Google Search Console submission and sitemap ping
const data = $('⚙️ Get Published Blog URL').first().json;
const wpResult = $('📝 Publish to WordPress').first().json;
const pinResults = $('📌 Post Pin to Pinterest').all().map(i => i.json);

const pinsPosted = pinResults.filter(r => r.id).length;

return [{ json: {
  product_id: data.product_id,

  // Blog results
  blog_url: data.blog_url,
  blog_platform: data.blog_platform,
  blog_post_id: data.post_id,
  featured_image: data.featured_image_url,

  // SEO
  primary_keyword: data.seo_meta?.focus_keyword,
  meta_title: data.seo_meta?.title,
  meta_description: data.seo_meta?.description,

  // Pinterest
  pins_posted: pinsPosted,
  pinterest_board: 'Productivity Board',

  // Indexing actions needed
  indexing_actions: [
    `Submit URL to Google Search Console: ${data.blog_url}`,
    `Ping sitemap: ${data.blog_url?.split('/').slice(0,3).join('/')}/sitemap.xml`,
    `Share on all social platforms with blog URL`,
    `Add internal links from other blog posts to this one`
  ],

  // Performance tracking
  tracking_setup: {
    google_analytics_event: `blog_published_${data.product_id}`,
    target_keyword: data.seo_meta?.primary_keyword,
    ranking_timeline: data.full_blog?.estimated_ranking_timeline || '3-6 months',
    check_ranking_after_days: 30
  },

  _completed_at: new Date().toISOString()
}}];
